import React, { useState, useEffect } from "react";
import "./Domains.css";

const API_URL = "http://localhost:8080/api/domains";

const DomainsList = () => {

  const [domains, setDomains] = useState([]);
  const [showForm, setShowForm] = useState(false);
  const [editingId, setEditingId] = useState(null);

  const [domain, setDomain] = useState({
    name: "",
    description: "",
  });


  /* ===========================
        LOAD FROM BACKEND
  =========================== */
  useEffect(() => {
    fetchDomains();
  }, []);


  const fetchDomains = async () => {

    try {

      const response = await fetch(API_URL);

      const data = await response.json();

      setDomains(data);

    } catch (error) {

      console.error("Error fetching domains:", error);

    }

  };


  /* ===========================
        INPUT CHANGE
  =========================== */
  const handleChange = (e) => {

    setDomain({
      ...domain,
      [e.target.name]: e.target.value,
    });

  };


  /* ===========================
        ADD NEW DOMAIN
  =========================== */
  const handleAdd = () => {

    setDomain({
      name: "",
      description: "",
    });

    setEditingId(null);

    setShowForm(true);

  };


  /* ===========================
        EDIT DOMAIN
  =========================== */
  const handleEdit = (dom) => {

    setDomain({
      name: dom.name,
      description: dom.description,
    });

    setEditingId(dom.id);

    setShowForm(true);

  };


  /* ===========================
        SAVE (ADD / UPDATE)
  =========================== */
  const handleSubmit = async (e) => {

    e.preventDefault();

    try {

      if (editingId) {

        // UPDATE
        await fetch(`${API_URL}/${editingId}`, {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify(domain),
        });

      } else {

        // CREATE
        await fetch(API_URL, {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify(domain),
        });

      }

      fetchDomains();

      setShowForm(false);

    } catch (error) {

      console.error("Error saving domain:", error);

    }

  };


  /* ===========================
        DELETE DOMAIN
  =========================== */
  const handleDelete = async (id) => {

    if (window.confirm("Are you sure to delete this domain?")) {

      try {

        await fetch(`${API_URL}/${id}`, {
          method: "DELETE",
        });

        fetchDomains();

      } catch (error) {

        console.error("Error deleting domain:", error);

      }

    }

  };


  return (

    <div className="department-scope">

      <h2>Manage Domains</h2>

      <button
        className="add-btn"
        onClick={handleAdd}
      >
        Add New Domain
      </button>


      <div className="department-table-card">

        <table className="department-table">

          <thead>

            <tr>
              <th>S No</th>
              <th>Domain Name</th>
              <th>Description</th>
              <th>Action</th>
            </tr>

          </thead>

          <tbody>

            {domains.map((dom, index) => (

              <tr key={dom.id}>

                <td>{index + 1}</td>

                <td>{dom.name}</td>

                <td>{dom.description}</td>

                <td>

                  <button
                    className="edit-btn"
                    onClick={() => handleEdit(dom)}
                  >
                    Edit
                  </button>

                  <button
                    className="delete-btn"
                    onClick={() => handleDelete(dom.id)}
                  >
                    Delete
                  </button>

                </td>

              </tr>

            ))}

            {domains.length === 0 && (

              <tr>

                <td colSpan="4" style={{ textAlign: "center" }}>
                  No Domains Found
                </td>

              </tr>

            )}

          </tbody>

        </table>

      </div>


      {showForm && (

        <div className="add-department-card">

          <h3>
            {editingId ? "Edit Domain" : "Add New Domain"}
          </h3>

          <form
            className="add-department-form"
            onSubmit={handleSubmit}
          >

            <div className="form-group">

              <label>Domain Name</label>

              <input
                type="text"
                name="name"
                value={domain.name}
                onChange={handleChange}
                required
              />

            </div>

            <div className="form-group">

              <label>Description</label>

              <textarea
                name="description"
                value={domain.description}
                onChange={handleChange}
              />

            </div>

            <div className="form-actions">

              <button type="submit" className="save-btn">
                {editingId ? "Update" : "Save"}
              </button>

              <button
                type="button"
                className="cancel-btn"
                onClick={() => setShowForm(false)}
              >
                Cancel
              </button>

            </div>

          </form>

        </div>

      )}

    </div>

  );

};

export default DomainsList;
